questions.answer:
Implement an Azure Functions HTTP-triggered /upload endpoint that accepts tenantId in the X-Tenant-ID header and multipart/form-data file uploads. Use Node.js with Azure SDK:

```javascript
const { CosmosClient } = require('@azure/cosmos');
const { BlobServiceClient } = require('@azure/storage-blob');
const { generateBlobSASQueryParameters, BlobSASPermissions } = require('@azure/storage-blob');

module.exports = async function (context, req) {
  const tenantId = req.headers['x-tenant-id'];
  if (!tenantId) {
    context.res = { status: 400, body: 'Missing X-Tenant-ID header' };
    return;
  }

  const file = req.files?.file;
  if (!file) {
    context.res = { status: 400, body: 'No file provided' };
    return;
  }

  try {
    // Initialize clients with Managed Identity
    const cosmosClient = new CosmosClient(process.env.COSMOS_ENDPOINT);
    const blobServiceClient = BlobServiceClient.fromConnectionString(process.env.BLOB_CONNECTION_STRING);

    // Store file in Blob Storage
    const containerClient = blobServiceClient.getContainerClient('tenant-files');
    const blobName = `${tenantId}/${file.originalname}`;
    const blockBlobClient = containerClient.getBlockBlobClient(blobName);

    await blockBlobClient.uploadData(file.buffer);

    // Generate SAS token (1 hour expiry)
    const sasToken = generateBlobSASQueryParameters({
      containerName: 'tenant-files',
      blobName: blobName,
      permissions: BlobSASPermissions.parse('r'),
      expiresOn: new Date(Date.now() + 3600000)
    }, blobServiceClient.credential).toString();

    // Store metadata in Cosmos DB
    const database = cosmosClient.database('DocumentDB');
    const container = database.container('metadata');

    const metadata = {
      id: `${tenantId}-${file.originalname}-${Date.now()}`,
      tenantId: tenantId,
      fileName: file.originalname,
      blobPath: blobName,
      fileSize: file.size,
      contentType: file.mimetype,
      uploadTimestamp: new Date().toISOString(),
      sasUrl: `${blockBlobClient.url}?${sasToken}`
    };

    await container.items.create(metadata);

    context.res = {
      status: 200,
      body: {
        fileId: metadata.id,
        fileName: file.originalname,
        sasUrl: metadata.sasUrl
      }
    };
  } catch (error) {
    context.log.error('Upload failed:', error);
    context.res = { status: 500, body: 'Upload failed' };
  }
};
```

## Architecture & Permissions

**Architecture**: Azure Functions HTTP trigger → Cosmos DB for metadata → Blob Storage for files. Per-tenant isolation via partitionKey and blob path structure.

**Permissions**: Use Managed Identity for Azure Functions to access Cosmos DB and Blob Storage. Grant Storage Blob Data Contributor role to the Function App's identity. Cosmos DB should have partitionKey=tenantId for scalable multi-tenant access.

**Unit Test**:

```javascript
const jest = require('jest');

describe('Upload Function', () => {
  test('should successfully upload file with valid tenantId', async () => {
    const mockContext = {
      log: { error: jest.fn() },
      res: {}
    };

    const mockReq = {
      headers: { 'x-tenant-id': 'tenant123' },
      files: {
        file: {
          originalname: 'test.pdf',
          buffer: Buffer.from('test content'),
          size: 12,
          mimetype: 'application/pdf'
        }
      }
    };

    // Mock Azure SDK calls
    jest.mock('@azure/storage-blob');
    jest.mock('@azure/cosmos');

    await require('../index')(mockContext, mockReq);

    expect(mockContext.res.status).toBe(200);
    expect(mockContext.res.body.fileName).toBe('test.pdf');
    expect(mockContext.res.body.sasUrl).toContain('tenant123/test.pdf');
  });

  test('should return 400 when tenantId is missing', async () => {
    const mockContext = { res: {} };
    const mockReq = { headers: {}, files: {} };

    await require('../index')(mockContext, mockReq);

    expect(mockContext.res.status).toBe(400);
    expect(mockContext.res.body).toBe('Missing X-Tenant-ID header');
  });
});
```

## Azure DevOps Pipeline

```yaml
# azure-pipelines.yml
trigger:
  branches:
    include:
    - main

pool:
  vmImage: 'windows-latest'

variables:
  - name: buildConfiguration
    value: 'Release'
  - group: 'azure-secrets' # Contains COSMOS_ENDPOINT, BLOB_CONNECTION_STRING

