const sharp = require('sharp');

module.exports = async function (context, myBlob) {
  const blobService = BlobServiceClient.fromConnectionString(process.env.AzureWebJobsStorage);
  const containerClient = blobService.getContainerClient('source');
  const thumbContainerClient = blobService.getContainerClient('thumbnails');

  const startTime = Date.now();
  const blobName = context.bindingData.name;

  // Idempotency check
  const blockBlob = thumbContainerClient.getBlockBlobClient(blobName);
  const exists = await blockBlob.exists();
  if (exists) {
    context.log(`Thumbnail already exists for ${blobName}`);
    return;
  }

  // Validate metadata
  const properties = await containerClient.getBlobClient(blobName).getProperties();
  const contentType = properties.contentType;
  const contentLength = properties.contentLength;

  if (!contentType?.startsWith('image/') || contentLength > 5 * 1024 * 1024) {
    throw new Error('Invalid image: must be image/* and <= 5MB');
  }

  // Resize and upload thumbnail
  const buffer = await containerClient.getBlobClient(blobName).downloadToBuffer();
  const thumbnail = await sharp(buffer).resize(64, 64).toBuffer();
  await blockBlob.upload(thumbnail, thumbnail.length);

  // Audit log to Table Storage
  const tableService = require('@azure/data-tables').TableClient.fromConnectionString(
    process.env.AzureWebJobsStorage, 'AuditLog'
  );
  await tableService.createEntity({
    partitionKey: 'thumbnails',
    rowKey: blobName,
    timestamp: new Date().toISOString(),
    status: 'success',
    durationMs: Date.now() - startTime
  });

  context.log(`Processed ${blobName} in ${Date.now() - startTime}ms`);
};
