    await redis.del(`tenant:${tenantId}:flags:${flagKey}`);
  } else {
    // Global flag changed - invalidate all tenant caches
    const keys = await redis.keys('tenant:*:flags:');
    if (keys.length > 0) await redis.del(...keys);
  }
};
