```javascript
// index.js
const { ContainerClient } = require('@azure/storage-blob');
const { CosmosClient } = require('@azure/cosmos');

module.exports = async function (context, req) {
    const tenantId = req.query.tenantId;
    const fileName = req.body?.filename || req.headers['x-filename'];

    if (!tenantId || !fileName) {
        context.res = { status: 400, body: 'Missing tenantId or fileName' };
        return;
    }

    const blobServiceClient = new ContainerClient(
        `https://${process.env.STORAGE_ACCOUNT}.blob.core.windows.net/${tenantId}`,
        new DefaultAzureCredential()
    );

    const blockBlobClient = blobServiceClient.getBlockBlobClient(fileName);
    const uploadStream = async (readableStream) => {
        let rowCount = 0;
        return new Promise((resolve, reject) => {
            readableStream.on('data', (data) => {
                rowCount += data.toString().split('\n').length - 1;
            });
            readableStream.on('end', () => resolve(rowCount));
            readableStream.on('error', reject);
        });
    };

    const stream = req.body;
    const rowCount = await uploadStream(stream);
    await blockBlobClient.uploadStream(stream);

    const cosmosClient = new CosmosClient({
        endpoint: process.env.COSMOS_ENDPOINT,
        credential: new DefaultAzureCredential()
    });

    const container = cosmosClient.database('ingestion').container('files');
    await container.items.upsert({
        id: `${tenantId}-${fileName}`,
        tenantId,
        fileName,
        uploadTime: new Date().toISOString(),
        rowCount
    });

    context.res = { status: 200, body: { rowCount } };
};
```

