## Function Layout

```javascript
// Timer-triggered starter (index.js)
module.exports = async function(context) {
  const client = new DurableFunctionClient();
  await client.startNew("ExportOrchestrator", undefined, { });
};

// Orchestrator (orchestrator.js)
async function* exportOrchestrator(context) {
  const exportRequest = context.df.getInput();

  // Idempotency check
  if (exportRequest.status !== "pending") {
    return { skipped: true, reason: "already processed" };
  }

  // Update status to processing
  yield context.df.callEntity(exportRequest.id, "updateStatus", "processing");

  // Gather tenant data
  const data = yield context.df.callActivity("GatherTenantData", exportRequest);

  // Write CSV to ADLS Gen2
  const blobPath = yield context.df.callActivity("WriteCsvToADLS", { 
    tenantId: exportRequest.tenantId, 
    data 
  });

  // Update status and callback
  yield context.df.callActivity("FinalizeExport", { 
    exportRequestId: exportRequest.id,
    blobPath 
  });

  return { success: true, blobPath };
}

// Activity: Gather data (activities/gatherData.js)
module.exports = async function(context) {
  const { tenantId, exportParams } = context.bindingData;
  const query = "SELECT * FROM c WHERE c.tenantId = @tenantId";
  return await cosmosClient.query({ query, parameters: [{ name: "@tenantId", value: tenantId }] });
};

// Activity: Write CSV (activities/writeCsv.js)
module.exports = async function(context) {
  const { tenantId, data } = context.bindingData;
  const timestamp = Date.now();
  const blobPath = `/exports/${tenantId}/export-${timestamp}.csv`;
  const csvContent = convertToCsv(data);
  await adlsClient.write(blobPath, csvContent);
  return blobPath;
};

// Activity: Webhook callback (activities/callback.js)
module.exports = async function(context) {
  const { webhookUrl, status, blobPath } = context.bindingData;
  await axios.post(webhookUrl, { status, blobPath });
};
```

