const ajv = new Ajv();
let schemaCache = new Map();
async function getSchemaForTenant(tenantId){
  if(schemaCache.has(tenantId)) return schemaCache.get(tenantId);
  const cfg = await AppConfigClient.getConfigurationSetting({key: `schema:${tenantId}`});
  const schema = JSON.parse(cfg.value);
  schemaCache.set(tenantId, schema);
  setTimeout(() => schemaCache.delete(tenantId), 60_000);
