}
async function validateAndRoute(msg){
  const tenantId = msg.tenantId;
  const schema = await getSchemaForTenant(tenantId);
  const validate = ajv.compile(schema);
  const valid = validate(msg.payload);
  if(!valid){ await DLQ.push({tenantId, msg, errors: validate.errors}); return; }
  await CosmosDB.upsert('events', tenantId, msg.payload, {dedupId: msg.id});
}
