  const res = await client.getConfigurationSetting({
    key: `.appconfig.featureflag/${feature}`,
    label: `tenant-${tenantId}`
  });
  const flag = JSON.parse(res.value);
  if (!flag.enabled) return false;
  const pct = (flag.conditions?.client_filters || [])
    .find(f => f.name === 'Percentage')?.parameters?.value ?? 100;
  let h = 7;
  for (const c of tenantId) h = (h * 31 + c.charCodeAt(0)) % 100;
  return h < pct;
}
