// Example: rough DP noise application (Gaussian approximation)
function gaussianNoise(scale) {
  // Box-Mellin or CLT-based approximation
  let u1 = Math.random(), u2 = Math.random();
  return scale * Math.sqrt(-2 * Math.log(u1)) * Math.cos(2 * Math.PI * u2);
}
