## Code Example
```javascript
const { CosmosClient } = require('@azure/cosmos');
const { AppConfigurationClient } = require('@azure/app-configuration');
const redis = require('redis');

module.exports = async function (context, req) {
  const tenantId = req.headers['x-tenant-id'] || req.params.tenantId;
  const productId = req.params.productId;
  const cacheKey = `pricing:${tenantId}:${productId}`;

  try {
    // Check Redis cache first
    const cached = await getCachedPrice(cacheKey);
    if (cached) {
      return { status: 200, body: cached };
    }

    // Cache miss - fetch from Cosmos DB
    const basePrice = await fetchBasePrice(tenantId, productId);

    // Get discount from App Config with fallback
    const discount = await fetchDiscount(tenantId);

    // Calculate final price
    const finalPrice = basePrice.price * (1 - discount);
    const result = {
      price: finalPrice,
      currency: basePrice.currency || 'USD',
      discountApplied: discount
    };

    // Cache result for 60s
    await setCachedPrice(cacheKey, result, 60);

    return { status: 200, body: result };

  } catch (error) {
    context.log.error('Pricing endpoint error:', error);
    return { 
      status: 500, 
      body: { error: 'Unable to fetch pricing information' } 
    };
  }
};

async function getCachedPrice(key) {
  try {
    const client = redis.createClient(process.env.REDIS_CONNECTION_STRING);
    const cached = await client.get(key);
    return cached ? JSON.parse(cached) : null;
  } catch (error) {
    console.error('Redis cache read failed:', error);
    return null; // Continue without cache
  }
}

async function setCachedPrice(key, value, ttlSeconds) {
  try {
    const client = redis.createClient(process.env.REDIS_CONNECTION_STRING);
    await client.setEx(key, ttlSeconds, JSON.stringify(value));
  } catch (error) {
    console.error('Redis cache write failed:', error);
    // Continue without caching
  }
}

async function fetchBasePrice(tenantId, productId) {
  const client = new CosmosClient(process.env.COSMOS_CONNECTION_STRING);
  const container = client.database('catalog').container('products');

  try {
    const { resource } = await container.item(productId, tenantId).read();
    if (!resource) throw new Error('Product not found');
    return resource;
  } catch (error) {
    // Fallback to default pricing structure
    return { price: 100.0, currency: 'USD' };
  }
}

async function fetchDiscount(tenantId) {
  const client = new AppConfigurationClient(process.env.APP_CONFIG_CONNECTION_STRING);

  try {
    const { value } = await client.getConfigurationSetting(
      { key: `pricing:discount:${tenantId}` }
    );
    return parseFloat(value) || 0;
  } catch (error) {
    try {
      // Fallback to global discount
      const { value } = await client.getConfigurationSetting(
        { key: 'pricing:discount:global' }
      );
      return parseFloat(value) || 0;
    } catch (globalError) {
      return 0; // No discount available
    }
  }
}
```

