  const { name, region } = req.body;

  // Validate required fields
  if (!tenantId || !name || !region) {
    return { status: 400, body: { error: 'Missing required fields' } };
  }

  // Check Redis cache
  const cacheKey = `tenants:${tenantId}`;
  let cached = await redis.get(cacheKey);

  if (!cached) {
    // Cache miss - write to Cosmos DB
    await cosmos.upsert({
      id: tenantId,
      PartitionKey: tenantId,
      tenantId,
      name,
      region
    });

    // Publish to Service Bus
    await serviceBus.publish('onboardingNotifications', {
      tenantId,
      name,
      region,
      timestamp: new Date().toISOString()
    });

    // Cache with 120s TTL
    await redis.setex(cacheKey, 120, JSON.stringify({ tenantId, name, region }));
  }

  return {
    status: 201,
    body: JSON.parse(cached) || { tenantId, name, region }
  };
};
```

