// Azure Function with Redis caching and SAS generation
const { BlobServiceClient } = require('@azure/storage-blob');
const redis = require('redis');

module.exports = async function (context, req) {
  const { tenantId, container, blobName } = req.params;
  const headerTenantId = req.headers['x-tenant-id'];
  const effectiveTenantId = headerTenantId || tenantId;

  const cacheKey = `token:${effectiveTenantId}:${container}:${blobName}`;

  try {
    // Try Redis cache first
    const cached = await redis.get(cacheKey);
    if (cached) {
      return { status: 200, body: JSON.parse(cached) };
    }
  } catch (redisError) {
    context.log.warn('Redis unavailable, generating new token');
  }

  // Generate new SAS token
  const blobServiceClient = BlobServiceClient.fromConnectionString(process.env.AZURE_STORAGE_CONNECTION);
  const containerClient = blobServiceClient.getContainerClient(container);
  const blobClient = containerClient.getBlobClient(blobName);

  const sasToken = await blobClient.generateBlobSasUrl({
    permissions: 'r',
    expiresOn: new Date(Date.now() + 5 * 60 * 1000)
  });

  const response = {
    token: sasToken,
    url: blobClient.url,
    expiry: new Date(Date.now() + 5 * 60 * 1000).toISOString()
  };

  // Cache the token
  try {
    await redis.setex(cacheKey, 300, JSON.stringify(response));
  } catch (cacheError) {
    context.log.warn('Failed to cache token');
  }

  return { status: 200, body: response };
};
```

