// Example Azure Function HTTP trigger with BlobOutput binding (Node.js)
module.exports = async function (context, req) {
  const tenantId = req.params.tenantId;
  const { fileName, contentBase64 } = req.body || {};

  // Validations
  if (!tenantId || !/^tenant-[a-z0-9-]+$/.test(tenantId)) {
    context.res = { status: 400, body: 'Invalid tenantId' };
    return;
  }
  if (!fileName || !contentBase64) {
    context.res = { status: 400, body: 'Missing fields' };
    return;
  }

  const buffer = Buffer.from(contentBase64, 'base64');
  if (buffer.length > 1024 * 1024) {
    context.res = { status: 413, body: 'File too large' };
    return;
  }

  // Blob path uses tenant-specific prefix
  const blobPath = `tenant-${tenantId}/${fileName}`;
  // Binding setup (depends on function.json):
  context.bindings.blobOut = { data: buffer, blobPath };

  context.res = { status: 200, body: 'Uploaded' };
};
```

