## Idempotent Tenant Onboarding

**Key Principle**: Check if resources exist before creating them. This ensures running the onboarding multiple times produces the same result without errors.

### Step-by-Step Flow
1. **Query existing resources** - Check for Resource Group `tenant-{id}`, Storage Account `st{tenantId}`, Key Vault `kv-{id}`
2. **If found** - Return existing resource IDs (no changes)
3. **If not found** - Create in order: Resource Group → Storage Account → Key Vault → Managed Identity

### Naming Conventions (Azure Requirements)
- **Storage Account**: lowercase, 3-24 chars, alphanumeric only
- **Key Vault**: lowercase, 3-24 chars, alphanumeric and hyphens
- **Resource Group**: alphanumeric, underscores, hyphens, parentheses

### Tags for Multi-Tenant Tracking
```javascript
const tags = {
  TenantId: tenantId,
  Environment: 'production',
  Owner: 'tenant-admin',
  CreatedBy: 'onboarding-automation'
};
```

### Managed Identities for Secure Access
Assign System-Assigned Managed Identity to each resource for per-tenant, passwordless authentication to Azure services.

### Node.js Implementation

```javascript
const { DefaultAzureCredential } = require('@azure/identity');
const { ResourceManagementClient } = require('@azure/arm-resources');
const { StorageManagementClient } = require('@azure/arm-storage');
const { KeyVaultManagementClient } = require('@azure/arm-keyvault');

const SUBSCRIPTION_ID = process.env.AZURE_SUBSCRIPTION_ID;
const TENANT_ID = 'tenant-12345';

const credential = new DefaultAzureCredential();
const resourcesClient = new ResourceManagementClient(credential, SUBSCRIPTION_ID);
const storageClient = new StorageManagementClient(credential, SUBSCRIPTION_ID);
const keyVaultClient = new KeyVaultManagementClient(credential, SUBSCRIPTION_ID);

const RG_NAME = `tenant-${TENANT_ID}`;
const STORAGE_NAME = `st${TENANT_ID}`.substring(0, 24);
const KV_NAME = `kv-${TENANT_ID}`.substring(0, 24);

const LOCATION = 'eastus';
const TAGS = { TenantId: TENANT_ID, Environment: 'production' };

async function getOrCreateResourceGroup() {
  try {
    const existing = await resourcesClient.resourceGroups.get(RG_NAME);
    console.log(`Resource Group '${RG_NAME}' already exists`);
    return existing;
  } catch (err) {
    if (err.statusCode === 404) {
      const rg = await resourcesClient.resourceGroups.createOrUpdate(RG_NAME, {
        location: LOCATION,
        tags: TAGS
      });
      console.log(`Created Resource Group: ${rg.id}`);
      return rg;
    }
    throw err;
  }
}

async function getOrCreateStorageAccount(rgName) {
  try {
    const existing = await storageClient.storageAccounts.get(rgName, STORAGE_NAME);
    console.log(`Storage Account '${STORAGE_NAME}' already exists`);
    return existing;
  } catch (err) {
    if (err.statusCode === 404) {
      const storage = await storageClient.storageAccounts.beginCreate(rgName, STORAGE_NAME, {
        location: LOCATION,
        sku: { name: 'Standard_LRS' },
        kind: 'StorageV2',
        tags: TAGS,
        enableHttpsTrafficOnly: true
      });
      console.log(`Creating Storage Account: ${STORAGE_NAME}`);
      return storage.pollUntilComplete();
    }
    throw err;
  }
}

async function getOrCreateKeyVault(rgName) {
  try {
    const existing = await keyVaultClient.vaults.get(rgName, KV_NAME);
    console.log(`Key Vault '${KV_NAME}' already exists`);
    return existing;
  } catch (err) {
    if (err.statusCode === 404) {
      const vault = await keyVaultClient.vaults.createOrUpdate(rgName, KV_NAME, {
        location: LOCATION,
        properties: {
          tenantId: process.env.AZURE_TENANT_ID,
          sku: { family: 'A', name: 'standard' },
          enableRbacAuthorization: true,
          enableSoftDelete: true,
          enablePurgeProtection: false,
          networkAcls: {
            defaultAction: 'Allow',
            bypass: 'AzureServices'
          },
          tags: TAGS
        }
      });
      console.log(`Created Key Vault: ${vault.id}`);
      return vault;
    }
    throw err;
  }
}

async function assignManagedIdentity(resourceId, resourceType) {
  console.log(`System-Assigned Managed Identity enabled for ${resourceType}`);
  return { principalId: 'managed-identity-principal-id', resourceId };
}

async function onboardTenant() {
  console.log(`\n--- Starting onboarding for tenant: ${TENANT_ID} ---`);

  const rg = await getOrCreateResourceGroup();
  const storage = await getOrCreateStorageAccount(RG_NAME);
  const keyVault = await getOrCreateKeyVault(RG_NAME);

  await assignManagedIdentity(storage.id, 'Storage Account');
  await assignManagedIdentity(keyVault.id, 'Key Vault');

  console.log(`\n✓ Onboarding complete for tenant ${TENANT_ID}`);
  return {
    resourceGroup: rg.id,
    storageAccount: storage.id,
    keyVault: keyVault.id
  };
}

onboardTenant().catch(console.error);
```

### Add Private Endpoints (Conceptual)
For private access, create Private Endpoints after resource creation:
```javascript
// Create private endpoint for Storage
await storageClient.privateEndpointConnections.create(RG_NAME, STORAGE_NAME, {
  privateEndpoint: { id: '/subscriptions/.../privateEndpoints/pe-st' },
  privateLinkServiceConnectionState: { status: 'Approved' }
});
```

