// Minimal outline showing Key Vault and Cosmos DB usage
const { DefaultAzureCredential } = require('@azure/identity');
const { SecretClient } = require('@azure/keyvault-secrets');
const { CosmosClient } = require('@azure/cosmos');

const credential = new DefaultAzureCredential();
const kv = new SecretClient(`https://MY_VAULT.vault.azure.net`, credential);

async function getCosmosConn() {
  const secret = await kv.getSecret('CosmosDBConnectionString');
  return secret.value;
}

async function storeEvent(tenantId, evt) {
  const conn = await getCosmosConn();
  const client = new CosmosClient(conn);
  const container = client.database('Telemetry').container('Events');
  await container.items.create({ ...evt, tenantId });
}
```

